namespace Workspace.__WsNamespacePrefix.__WsAssemblyName
{
	public class FMM_DynGVSvc : IWsasDynamicGridV800
	{
        /// <summary>
        /// Retrieves paginated, filtered, and sorted data for display in the Dynamic Grid component.
        /// This method is called by the grid component whenever data needs to be refreshed (initial load, pagination, filtering, sorting).
        /// 
        /// Key Responsibilities:
        /// 1. Extract pagination parameters (startRowIndex, pageSize)
        /// 2. Extract filter criteria from pagedGridColumnFilters
        /// 3. Extract sort criteria from dbOrderBys
        /// 4. Retrieve XFDataTable by executing database query or by some other means using these parameters
        /// 5. Return XFDataTable with the result set
        /// 
        /// Performance Considerations:
        /// - Only retrieve the page of data requested (use startRowIndex and pageSize)
        /// - Apply filters and sorts at the database level, not in memory
        /// - Consider using stored procedures for complex queries
        /// - Page size is limited to 3000 rows per page
        /// </summary>
        public XFDynamicGridGetDataResult GetDynamicGridData(SessionInfo si, BRGlobals brGlobals, DashboardWorkspace workspace, DashboardDynamicGridArgs args)
        {
            try
            {
                if ((brGlobals != null) && (workspace != null) && (args != null))
                {
                    // Use args.GetDataArgs.StartRowIndex and args.GetDataArgs.PageSize to determine which page of data to retrieve.
					int startRowIndex = args.GetDataArgs.StartRowIndex;
					int pageSize = args.GetDataArgs.PageSize;
					
                    // Use args.GetDataArgs.PagedGridColumnFilters to handle any filtering applied to the grid and
					// args.GetDataArgs.PagedGridDbOrderBys to handle the sorting of data.
					List<PagedGridColumnFilter> pagedGridColumnFilters = args.GetDataArgs.PagedGridColumnFilters;
					List<DbOrderBy> dbOrderBys = args.GetDataArgs.PagedGridDbOrderBys;
					
					// Insert logic here to retrieve an XFDataTable using the startRowIndex, pageSize, pagedGridColumnFilters
					// and dbOrderBys. This XFDataTable is the data to be shown in the grid's currently selected page with
					// the grid's current filter and sorts applied on its columns.
					XFDataTable result = null;
					
					// Optionally build column definitions and row formats.
					List<XFDynamicGridColumnDefinition> columnDefinitions = null;
					List<XFDynamicGridRowFormat> rowFormats = null;
					
					return new XFDynamicGridGetDataResult(result, columnDefinitions, rowFormats, DataAccessLevel.AllAccess);
                }

                return null;
            }
            catch (Exception ex)
            {
                throw new XFException(si, ex);
            }
        }

		/// <summary>
        /// Saves edited data from the Dynamic Grid component back to the data source.
        /// This method is called when users press save after inserting, updating, or deleting rows in the grid.
        /// 
		/// Key Responsibilities:
        /// 1. Extract edited rows from args.SaveDataArgs.EditedDataRows
        /// 2. Determine which rows were inserted, updated, or deleted
        /// 3. Apply changes to the data source
        /// 4. Return updated data for the current page
        /// 
        /// IMPORTANT: 
        /// - Validate data before saving (business rules, constraints, etc.)
        /// - Handle concurrency conflicts (optimistic/pessimistic locking)
        /// - The return result MUST include the DataTable property with updated data
        /// </summary>
        public XFDynamicGridSaveDataResult SaveDynamicGridData(SessionInfo si, BRGlobals brGlobals, DashboardWorkspace workspace, DashboardDynamicGridArgs args)
        {
            try
            {
                if ((brGlobals != null) && (workspace != null) && (args != null))
                {
                    // Use args.SaveDataArgs.EditedDataRows to get the list of rows that were inserted, updated, or deleted.
					List<XFEditedDataRow> editedDataRows = args.SaveDataArgs.EditedDataRows;
					
					// Insert logic here to save edited data from the Dynamic Grid component back to the data source
					// using editedDataRows.
					
					// IMPORTANT: The return result object must include the DataTable property populated with the updated data.
					// Can utilize the GetDynamicGridData method above.
					XFDynamicGridGetDataResult getDataResult = GetDynamicGridData(si, brGlobals, workspace, args);
					
					// Create and return the save data result.
					XFDynamicGridSaveDataResult result = new XFDynamicGridSaveDataResult();
					result.DataTable = getDataResult?.DataTable;
					result.RowFormats = getDataResult?.RowFormats;
					result.PageIndex = (args.GetDataArgs.StartRowIndex / args.GetDataArgs.PageSize);
					result.IndexOfSelectedRowOnPage = 0;
					result.SaveDataTaskResult = new XFDynamicGridSaveDataTaskResult()
					{
						IsOK = true,
						ShowMessageBox = false,
						Message = ""
					};
					return result;
                }

                return null;
            }
            catch (Exception ex)
            {
                throw new XFException(si, ex);
            }
        }
	}
}

